# Load allowed plugin checksums from the allowed_plugins.conf file
sub load_allowed_checksums {
    my %allowed;
    if (-f $ALLOWED_PLUGINS_FILE) {
        open my $fh, '<', $ALLOWED_PLUGINS_FILE
            or croak "Cannot open allowed plugins file: $!";
        while (my $line = <$fh>) {
            chomp $line;
            $line =~ s/#.*//;
            $line =~ s/^\s+|\s+$//g;
            next unless $line;
            if ($line =~ /^([a-f0-9]{64})\s+(\S+)$/) {
                $allowed{$2} = $1;
            }
        }
        close $fh;
    }
    return \%allowed;
}

# Log plugin execution events
sub log_event {
    my ($level, $message) = @_;
    my $timestamp = localtime();
    if (open my $fh, '>>', $LOG_FILE) {
        print $fh "[$timestamp] [$level] $message\n";
        close $fh;
    }
    if ($level eq 'ERROR' || $level eq 'SECURITY') {
        warn "[$level] $message\n";
    }
}

# Validate plugin code against blocked patterns
sub validate_code {
    my ($code, $plugin_name) = @_;

    # Check code size
    if (length($code) > $MAX_CODE_SIZE) {
        log_event('SECURITY', "Plugin '$plugin_name' exceeds maximum code size limit");
        return 0;
    }

    # Check for null bytes
    if ($code =~ /\x00/) {
        log_event('SECURITY', "Plugin '$plugin_name' contains null bytes");
        return 0;
    }

    # Check against all blocked patterns
    for my $pattern (@BLOCKED_PATTERNS) {
        if ($code =~ $pattern) {
            log_event('SECURITY', "Plugin '$plugin_name' contains blocked pattern: $pattern");
            return 0;
        }
    }

    # Check for balanced braces (basic syntax sanity)
    my $brace_count = 0;
    for my $char (split //, $code) {
        $brace_count++ if $char eq '{';
        $brace_count-- if $char eq '}';
        if ($brace_count < 0) {
            log_event('SECURITY', "Plugin '$plugin_name' has unbalanced braces");
            return 0;
        }
    }
    if ($brace_count != 0) {
        log_event('SECURITY', "Plugin '$plugin_name' has unbalanced braces");
        return 0;
    }

    return 1;
}

# Verify plugin integrity via SHA-256 checksum
sub verify_integrity {
    my ($code, $plugin_name, $allowed_checksums) = @_;

    my $checksum = sha256_hex($code);

    unless (exists $allowed_checksums->{$plugin_name}) {
        log_event('SECURITY', "Plugin '$plugin_name' is not in the allowed plugins list");
        return 0;
    }

    unless ($checksum eq $allowed_checksums->{$plugin_name}) {
        log_event('SECURITY',
            "Plugin '$plugin_name' checksum mismatch. Expected: $allowed_checksums->{$plugin_name}, Got: $checksum");
        return 0;
    }

    log_event('INFO', "Plugin '$plugin_name' integrity verified (checksum: $checksum)");
    return 1;
}

# Load plugin code from a file within the plugin directory
sub load_plugin_file {
    my ($plugin_name) = @_;

    # Sanitize plugin name - only allow alphanumeric, underscore, hyphen
    unless ($plugin_name =~ /^[a-zA-Z0-9_-]+$/) {
        log_event('SECURITY', "Invalid plugin name: '$plugin_name'");
        return undef;
    }

    my $plugin_path = File::Spec->catfile($PLUGIN_DIR, "${plugin_name}.conf");

    # Resolve to absolute path and verify it's within plugin directory
    my $abs_plugin_path = File::Spec->rel2abs($plugin_path);
    my $abs_plugin_dir  = File::Spec->rel2abs($PLUGIN_DIR);

    unless ($abs_plugin_path =~ /^\Q$abs_plugin_dir\E/) {
        log_event('SECURITY', "Path traversal attempt detected for plugin '$plugin_name'");
        return undef;
    }

    unless (-f $plugin_path && -r $plugin_path) {
        log_event('ERROR', "Plugin file not found or not readable: $plugin_path");
        return undef;
    }

    open my $fh, '<', $plugin_path
        or do {
        log_event('ERROR', "Cannot open plugin file '$plugin_path': $!");
        return undef;
    };

    local $/;
    my $code = <$fh>;
    close $fh;

    return $code;
}

