    $context_setup
    my \$_plugin_output = '';
    local *STDOUT;
    open(STDOUT, '>', \\\$_plugin_output) or die "Cannot redirect STDOUT";
    $code
    \$_plugin_output;
};
END_SANDBOX

    return $sandboxed;
}

